# --- Query Cost Estimation Extension ---

from strawberry.extensions import SchemaExtension
from graphql import DocumentNode


class QueryCostLimiter(SchemaExtension):
    """
    Custom extension that estimates query cost based on field depth and list fields,
    and rejects queries that exceed the maximum allowed cost.
    """

    def on_operation(self):
        # Estimate cost before execution
        execution_context = self.execution_context
        document: Optional[DocumentNode] = execution_context.graphql_document
        if document:
            cost = self._estimate_cost(document)
            logger.info(f"Estimated query cost: {cost}")
            if cost > MAX_QUERY_COST:
                raise Exception(
                    f"Query too complex. Estimated cost {cost} exceeds maximum allowed cost {MAX_QUERY_COST}. "
                    f"Please reduce the depth or breadth of your query."
                )
        yield

    def _estimate_cost(self, document: DocumentNode, default_list_size: int = 10) -> int:
        """Estimate the cost of a GraphQL document."""
        from graphql.language import ast as gql_ast

        total_cost = 0

        def _visit_selections(selections, multiplier=1):
            nonlocal total_cost
            if not selections:
                return
            for selection in selections:
                if isinstance(selection, gql_ast.FieldNode):
                    field_name = selection.name.value
                    # List fields have a multiplier effect
                    list_fields = {
                        'products', 'reviews', 'categories', 'images',
                        'children', 'allProducts', 'allCategories', 'allSellers',
                    }
                    if field_name in list_fields:
                        # Check for limit argument
                        limit = default_list_size
                        if selection.arguments:
                            for arg in selection.arguments:
                                if arg.name.value == 'limit' and hasattr(arg.value, 'value'):
                                    try:
                                        limit = int(arg.value.value)
                                    except (ValueError, TypeError):
                                        pass
                        limit = min(limit, 100)  # Cap at max
                        total_cost += multiplier * limit
                        if selection.selection_set:
                            _visit_selections(
                                selection.selection_set.selections,
                                multiplier * limit
                            )
                    else:
                        total_cost += multiplier
                        if selection.selection_set:
                            _visit_selections(
                                selection.selection_set.selections,
                                multiplier
                            )
                elif isinstance(selection, gql_ast.InlineFragmentNode):
                    if selection.selection_set:
                        _visit_selections(selection.selection_set.selections, multiplier)
                elif isinstance(selection, gql_ast.FragmentSpreadNode):
                    # Fragment spreads would need fragment resolution; add base cost
                    total_cost += multiplier

        for definition in document.definitions:
            if hasattr(definition, 'selection_set') and definition.selection_set:
                _visit_selections(definition.selection_set.selections)

        return total_cost


